// Weapon -> attack-motion lookup, derived verbatim from roBrowserLegacy
// (src/DB/Jobs/WeaponAction.js + Items/WeaponTypeExpansion.js, MIT) — do not edit
// by hand; regenerate via the gen script. Maps a player job + weapon type to
// roBrowser's attack-motion index 0/1/2, rendered as action TYPE [5,10,11]
// (ATTACK1/2/3). The weapon `view` we send (iteminfo ClassNum) can be a SPECIFIC
// weapon id (e.g. Main_Gauche=31) rather than the base category; EXPANSION folds
// those back to the base type (Main_Gauche->SHORTSWORD) before the lookup, which is
// what decides the attack motion (and thus whether the weapon sprite shows). A few
// job families (novice/wizard/supernovice/linker) differ by sex. Unknown -> ATTACK1.

type MotionTable = Record<number, number>;
type Entry = { m: MotionTable; f?: MotionTable };

